import Navbar from "../../components/Navbar/Navbar";
import SummaryCard from '../../components/SummaryCard/SummaryCard';
import TransactionRow from '../../components/TransactionRow/TransactionRow';
import TransactionForm from '../../components/TransactionForm/TransactionForm';
import "./Dashboard.css";
import { useState } from "react";

function Dashboard() {
  const [transactions, setTransactions] = useState([]);
  const [amount, setAmount] = useState("");
  return (
    <>
    <div className="dashboard-container">
      <Navbar />
      <p className="main-heading">Summary</p>
      <div className="summary-container">
        <SummaryCard title="Income" amount={amount} className="income"/>
        <SummaryCard title="Expenses" amount="40000" className="expenses"/>
        <SummaryCard title="Balance" amount="60000" className="balance"/>
      </div>
      <p className="main-heading">Recent Transactions</p>   
      {transactions.map((transaction) => (
        <TransactionRow key={transaction.id} transaction={transaction} transactions={transactions} setTransactions={setTransactions}/>
      ))} 
      <TransactionForm transactions={transactions} setTransactions={setTransactions} amount={amount}/>  
    </div>
    </>
  );
}

export default Dashboard;
